// HasActorUser applies the HasEdge predicate on the "actor_user" edge.
func HasActorUser() predicate.FinancialAuditLog {
	return predicate.FinancialAuditLog(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ActorUserTable, ActorUserColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasActorUserWith applies the HasEdge predicate on the "actor_user" edge with a given conditions (other predicates).
func HasActorUserWith(preds ...predicate.User) predicate.FinancialAuditLog {
	return predicate.FinancialAuditLog(func(s *sql.Selector) {
		step := newActorUserStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

